def get_icon_svg(icon_name: str) -> str:
    """获取图标SVG字符串"""
    return ICONS.get(icon_name, ICONS.get("alert-circle", ""))


def get_icon_pixmap(icon_name: str, size: int = 24, color: str = "#FFFFFF") -> QPixmap:
    """
    获取图标QPixmap
    
    Args:
        icon_name: 图标名称
        size: 图标大小
        color: 图标颜色 (十六进制颜色字符串)
    
    Returns:
        QPixmap对象
    """
    svg_template = get_icon_svg(icon_name)
    if not svg_template:
        return QPixmap()
    
    # 替换颜色
    svg_colored = svg_template.replace('stroke="currentColor"', f'stroke="{color}"')
    
    # 创建SVG渲染器
    renderer = QSvgRenderer(QByteArray(svg_colored.encode('utf-8')))
    
    # 创建Pixmap
    pixmap = QPixmap(size, size)
    pixmap.fill(Qt.GlobalColor.transparent)
    
    painter = QPainter(pixmap)
    renderer.render(painter)
    painter.end()
    
    return pixmap


class IconManager:
    """图标管理器 - 缓存和提供图标"""
    
    _cache = {}
    
    @classmethod
    def get_icon(cls, icon_name: str, size: int = 24, color: str = "#FFFFFF") -> QPixmap:
        """获取图标(带缓存)"""
        cache_key = f"{icon_name}_{size}_{color}"
        
        if cache_key not in cls._cache:
            cls._cache[cache_key] = get_icon_pixmap(icon_name, size, color)
        
        return cls._cache[cache_key]
    
    @classmethod
    def clear_cache(cls):
        """清除缓存"""
        cls._cache.clear()


